var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var prices = global.get("fve_prices_forecast") || [];
// v18.21: Forecast z input_number entit (primв”ңГӯrnв”ңЕҹ zdroj)
var forecastZitraIN = global.get("homeassistant.homeAssistant.states['input_number.predpoved_solarni_vyroby_zitra']");
var forecastZitraKwh = (forecastZitraIN && forecastZitraIN.state && !isNaN(parseFloat(forecastZitraIN.state)))
    ? parseFloat(forecastZitraIN.state) : 0;
var forecastZitra = (forecastZitraKwh > 0) ? forecastZitraKwh : (global.get("forecast_vyroba_zitra") || 0);
// v18.21: Zbв”ңЕ»vajв”ңЕҹcв”ңЕҹ vв”ңЕ»roba z input_number entity (primв”ңГӯrnв”ңЕҹ zdroj)
var zbyvajiciIN = global.get("homeassistant.homeAssistant.states['input_number.zbyvajici_solarni_vyroba_dnes']");
var zbyvajiciKwh = (zbyvajiciIN && zbyvajiciIN.state && !isNaN(parseFloat(zbyvajiciIN.state)))
    ? parseFloat(zbyvajiciIN.state) : 0;
var zbyvajiciSolar = (zbyvajiciKwh > 0) ? zbyvajiciKwh : (global.get("zbyvajici_solar_dnes") || 0);
var consumptionAnalysis = global.get("fve_consumption_analysis") || {};
var consumptionPredictions = global.get("fve_consumption_predictions") || [];

// v17: в”ҖГ®tenв”ңЕҹ vв”ңЕ»chodu/zв”ңГӯpadu slunce z HA entit
// Tyto entity obsahujв”ңЕҹ ISO datetime string, extrahujeme hodinu
var sunRising = global.get("homeassistant.homeAssistant.states['sensor.sun_next_rising']") || {};
var sunSetting = global.get("homeassistant.homeAssistant.states['sensor.sun_next_setting']") || {};
var sunNoon = global.get("homeassistant.homeAssistant.states['sensor.sun_next_noon']") || {};

// Parsovв”ңГӯnв”ңЕҹ hodiny z ISO stringu nebo state value
function parseHourFromEntity(entity) {
    var state = (entity && entity.state) ? entity.state : null;
    if (!state) return null;
    // State je ISO datetime: "2026-02-19T06:45:00+01:00" nebo podobnв”ңЕ» formв”ңГӯt
    var d = new Date(state);
    if (isNaN(d.getTime())) return null;
    return d.getHours();
}

var sunriseHour = parseHourFromEntity(sunRising);
var sunsetHour = parseHourFromEntity(sunSetting);

// Solв”ңГӯrnв”ңЕҹ okno: sunrise + 1h offset (slunce musв”ңЕҹ bв”ңЕ»t vв”ңЕ»в”јГӯ) aв”јЕј sunset
// Fallback na config hodnoty pokud entity nejsou dostupnв”ңДҷ
var solarStart = (sunriseHour !== null) ? Math.max(sunriseHour + 1, 7) : 9;
var solarEnd = (sunsetHour !== null) ? Math.min(sunsetHour, 20) : 17;

msg.planData = {
    config: config,
    status: status,
    prices: prices,
    forecast: {
        zitra: forecastZitra,
        dnes: (function() {
    var dnesIN = global.get("homeassistant.homeAssistant.states['input_number.predpoved_solarni_vyroby_dnes']");
    var dnesKwh = (dnesIN && dnesIN.state && !isNaN(parseFloat(dnesIN.state))) ? parseFloat(dnesIN.state) : 0;
    return (dnesKwh > 0) ? dnesKwh : (global.get("forecast_vyroba_dnes") || 0);
})()
    },
    zbyvajiciSolar: zbyvajiciSolar,
    consumptionAnalysis: consumptionAnalysis,
    consumptionPredictions: consumptionPredictions,
    // v17: Dynamickв”ңДҷ solв”ңГӯrnв”ңЕҹ hodiny z HA
    solarStartHour: solarStart,
    solarEndHour: solarEnd,
    sunriseHour: sunriseHour,
    sunsetHour: sunsetHour,
    timestamp: new Date().toISOString()
};

node.status({fill:"blue", shape:"dot", text:"Solar: " + Math.round(zbyvajiciSolar) + "kWh | Г”ЕӣГҮ" + solarStart + "-" + solarEnd + "h"});
return msg;

// FVE Smart Plan v18.22 - mв”ҖЕӨsв”ңЕҹв”ҖЕ№nв”ңЕҹ solв”ңГӯrnв”ңЕҹ kв”јГ–ivky + cap forecastZitra
// v17.0 Opravy:
//   1. targetSocFromGrid: nabв”ңЕҹjet JEN pokud currentSoc nestaв”ҖЕ№в”ңЕҹ na drahв”ңДҷ hodiny pв”јГ–ed solarem
//      - Starв”ңЕ» projectedEndSoc byl в”јГӯpatnв”ҖЕӨ (poв”ҖЕ№в”ңЕҹtal drain i v в”јГЎetв”јГ–it kde SOC zв”јВ»stв”ңГӯvв”ңГӯ)
//      - Novв”ңЕ»: realDrain = POUZE drahв”ңДҷ hodiny * socDropNormal
//   2. solar_start/end_hour z HA entit (sensor.sun_next_rising/setting)
//   3. Maintenance charge: 20 dnв”ңЕҹ, pouze v zimв”ҖЕӨ (в”јГ–в”ңЕҹjen-bв”јГ–ezen)
// Pravidla:
//   - Solв”ңГӯrnв”ңЕҹ nabв”ңЕҹjenв”ңЕҹ mв”ңГӯ Vв”јЕ»DY pв”јГ–ednost pв”јГ–ed nabв”ңЕҹjenв”ңЕҹm ze sв”ңЕҹtв”ҖЕӨ
//   - Nabв”ңЕҹjet ze sв”ңЕҹtв”ҖЕӨ POUZE pokud baterie nestaв”ҖЕ№в”ңЕҹ do solaru
//   - Baterie by mв”ҖЕӨla bв”ңЕ»t в”ҖЕ№asto blв”ңЕҹzko minSoc pв”јГ–ed solв”ңГӯrnв”ңЕҹm nabв”ңЕҹjenв”ңЕҹm
//   - NORMAL = vybв”ңЕҹjenв”ңЕҹ baterie (drahв”ңДҷ + stв”јГ–ednв”ңЕҹ hodiny dle kapacity)
//   - в”јГЎETв”јЕӣIT = baterie zamв”ҖЕ№enв”ңГӯ (SOC se nemв”ҖЕӨnв”ңЕҹ)

var data = msg.planData;
var config = data.config || {};
var status = data.status || {};
var forecast = data.forecast || {};

var prices = data.prices || global.get("fve_prices_forecast") || [];

var MODY = {
    NORMAL: "normal",
    SETRIT: "setrit",
    NABIJET_ZE_SITE: "nabijet_ze_site",
    PRODAVAT: "prodavat",
    ZAKAZ_PRETOKU: "zakaz_pretoku",
    SOLAR_CHARGING: "solar_charging"
};

// === PARAMETRY Z CONFIGU ===
var kapacitaBaterie = config.kapacita_baterie_kwh || 28;
var minSoc = config.min_soc || 20;
var maxDailySoc = config.max_daily_soc || 80;
var amortizace = config.amortizace_baterie_czk_kwh || 1.5;
var chargeEfficiency = config.charge_efficiency || 0.90;
var dischargeEfficiency = config.discharge_efficiency || 0.90;
var roundTripEfficiency = chargeEfficiency * dischargeEfficiency;
var chargeRateKwh = config.charge_rate_kwh || 5;
var socDropNormal = config.soc_drop_normal_pct || 5;
var dailyConsumptionKwh = config.daily_consumption_kwh || 20;
var PRAH_LEVNA = config.prah_levna_energie || 4;
var PRAH_DRAHA = config.prah_draha_energie || 12;
var horizont = config.plan_horizon_hours || 12;
var maxGridW = config.max_spotreba_sit_w || 22000;
var maxFeedInW = config.max_feed_in_w || 7600;
var prodejZBaterieEnabled = config.prodej_z_baterie_enabled === true;
var blokaceVybijeni = config.blokace_vybijeni === true;
var manualMod = config.manual_mod || "auto";
var letniRezim = config.letni_rezim === true;
var socDropSetrit = config.soc_drop_setrit_pct || 1;
var minDischargeBlokaceW = config.min_vybijeni_blokace_w || 1300;
// v18.8: SOC drop pв”јГ–i blokaci (1.3kW povinnв”ңГӯ spotв”јГ–eba domu)
var socDropBlokace = (minDischargeBlokaceW / 1000 / kapacitaBaterie) * 100;

// v17: Dynamickв”ңДҷ solв”ңГӯrnв”ңЕҹ hodiny z HA (pв”јГ–edanв”ңДҷ z Sbв”ңЕҹrka dat)
var solarStartHour = data.solarStartHour || config.solar_start_hour || 9;
var solarEndHour = data.solarEndHour || config.solar_end_hour || 17;

// === AKTUв”ңГјLNв”ңЕ№ STAV ===
var currentSoc = status.battery_soc || 50;

// v18.2: Blokace info pro dashboard
var cerpadloTopi = global.get("cerpadlo_topi") || false;
var autoNabijeni = global.get("auto_nabijeni_aktivni") || false;
var saunaAktivni = global.get("sauna_aktivni") || false;
var blokaceItems = [];
if (cerpadloTopi) blokaceItems.push("topenв”ңЕҹ");
if (autoNabijeni) blokaceItems.push("auto");
if (saunaAktivni) blokaceItems.push("sauna");
var blokaceText = blokaceItems.length > 0 ? "ANO - " + blokaceItems.join(", ") : "NE";
var forecastZitra = forecast.zitra || 0;
var remainingSolarKwh = data.zbyvajiciSolar || 0;

// v18.13: Sanity check - max dennв”ңЕҹ vв”ңЕ»roba dle mв”ҖЕӨsв”ңЕҹce pro 17kWp, az190, sklon45, 50N
// Hodnoty odpovв”ңЕҹdajв”ңЕҹ realistickв”ңДҷmu maximu pro danв”ңЕ» mв”ҖЕӨsв”ңЕҹc
// v18.20: Realistickв”ңГӯ maxima pro 17kWp, az190, sklon45, 50N (Horouв”јГӯany)
var monthMaxSolarKwh = [15, 35, 60, 90, 110, 120, 115, 105, 75, 50, 20, 12];
var currentMonth = new Date().getMonth(); // 0-11
var maxSolarToday = monthMaxSolarKwh[currentMonth];
if (remainingSolarKwh > maxSolarToday) {
    remainingSolarKwh = maxSolarToday;
}
// v18.22: Cap forecastZitra stejnв”ҖЕӨ jako remainingSolar
// VRM API mв”јВ»в”јЕјe vracet nerealisticky vysokв”ңДҷ hodnoty (56 kWh v в”ңв•‘noru)
// Zв”ңЕҹtв”јГ–ek: pokud jsme poslednв”ңЕҹch 3 dny v mв”ҖЕӨsв”ңЕҹci, pouв”јЕјв”ңЕҹt max(aktuв”ңГӯlnв”ңЕҹ, pв”јГ–в”ңЕҹв”јГӯtв”ңЕҹ mв”ҖЕӨsв”ңЕҹc)
var dayOfMonth = new Date().getDate();
var daysInMonth = new Date(new Date().getFullYear(), currentMonth + 1, 0).getDate();
var maxSolarForTomorrow = maxSolarToday;
if (dayOfMonth >= daysInMonth - 2) {
    var nextMonthMax = monthMaxSolarKwh[(currentMonth + 1) % 12];
    maxSolarForTomorrow = Math.max(maxSolarToday, nextMonthMax);
}
if (forecastZitra > maxSolarForTomorrow) {
    forecastZitra = maxSolarForTomorrow;
}

// v18: Predikce vв”ңЕ»roby a spotв”јГ–eby per hodinu z historie
var consumptionPredictions = data.consumptionPredictions || [];

// v18: Pomocnв”ңГӯ funkce - zв”ңЕҹskej predikci pro danou hodinu
function getPredictionForHour(hour) {
    for (var pi = 0; pi < consumptionPredictions.length; pi++) {
        if (consumptionPredictions[pi].hour === hour) {
            return consumptionPredictions[pi];
        }
    }
    return null;
}

// v18: Vв”ңЕ»poв”ҖЕ№et solв”ңГӯrnв”ңЕҹho pв”јГ–в”ңЕҹrв”јВ»stku per hodinu
// v18.22: Mв”ҖЕӨsв”ңЕҹв”ҖЕ№nв”ңЕҹ solв”ңГӯrnв”ңЕҹ kв”јГ–ivky pro Horouв”јГӯany (50.105N, 14.741E)
// Azimut 190в”¬в–‘ (JZ), sklon 45в”¬в–‘, 17 kWp
// Kaв”јЕјdв”ңЕ» mв”ҖЕӨsв”ңЕҹc mв”ңГӯ vlastnв”ңЕҹ distribuci vв”ңЕ»roby per hodina (normalizovв”ңГӯno na 1.0)
// Zima: krв”ңГӯtkв”ңЕ» den, vв”ңЕ»roba soustв”јГ–edв”ҖЕӨna kolem poledne
// Lв”ңДҷto: dlouhв”ңЕ» den, vв”ңЕ»roba rozprostв”јГ–ena, dв”јГ–в”ңЕҹvв”ҖЕӨjв”јГӯв”ңЕҹ start
var monthlySolarCurves = {
    // Leden (index 0): vв”ңЕ»chod ~7:50, zв”ңГӯpad ~16:20, krв”ңГӯtkв”ңЕ» den
    0:  {8: 0.02, 9: 0.08, 10: 0.14, 11: 0.18, 12: 0.20, 13: 0.18, 14: 0.12, 15: 0.06, 16: 0.02},
    // в”ңГңnor: vв”ңЕ»chod ~6:50, zв”ңГӯpad ~17:15
    1:  {7: 0.01, 8: 0.04, 9: 0.09, 10: 0.14, 11: 0.17, 12: 0.19, 13: 0.17, 14: 0.11, 15: 0.06, 16: 0.02},
    // Bв”јГ–ezen: vв”ңЕ»chod ~6:00, zв”ңГӯpad ~18:00
    2:  {6: 0.01, 7: 0.02, 8: 0.06, 9: 0.10, 10: 0.13, 11: 0.15, 12: 0.16, 13: 0.14, 14: 0.11, 15: 0.07, 16: 0.04, 17: 0.01},
    // Duben: vв”ңЕ»chod ~5:20, zв”ңГӯpad ~19:30
    3:  {5: 0.01, 6: 0.02, 7: 0.04, 8: 0.07, 9: 0.10, 10: 0.12, 11: 0.14, 12: 0.14, 13: 0.13, 14: 0.10, 15: 0.07, 16: 0.04, 17: 0.02},
    // Kvв”ҖЕӨten: vв”ңЕ»chod ~4:30, zв”ңГӯpad ~20:20
    4:  {5: 0.01, 6: 0.03, 7: 0.05, 8: 0.08, 9: 0.10, 10: 0.12, 11: 0.13, 12: 0.13, 13: 0.12, 14: 0.10, 15: 0.07, 16: 0.04, 17: 0.02},
    // в”ҖГ®erven: vв”ңЕ»chod ~4:10, zв”ңГӯpad ~20:50 (nejdelв”јГӯв”ңЕҹ den)
    5:  {5: 0.02, 6: 0.03, 7: 0.05, 8: 0.08, 9: 0.10, 10: 0.12, 11: 0.13, 12: 0.13, 13: 0.12, 14: 0.10, 15: 0.07, 16: 0.04, 17: 0.01},
    // в”ҖГ®ervenec: podobnв”ңЕ» в”ҖЕ№ervnu
    6:  {5: 0.02, 6: 0.03, 7: 0.05, 8: 0.08, 9: 0.10, 10: 0.12, 11: 0.13, 12: 0.13, 13: 0.12, 14: 0.10, 15: 0.07, 16: 0.04, 17: 0.01},
    // Srpen: vв”ңЕ»chod ~5:00, zв”ңГӯpad ~20:00
    7:  {5: 0.01, 6: 0.02, 7: 0.05, 8: 0.08, 9: 0.10, 10: 0.12, 11: 0.14, 12: 0.14, 13: 0.12, 14: 0.10, 15: 0.07, 16: 0.04, 17: 0.01},
    // Zв”ңГӯв”јГ–в”ңЕҹ: vв”ңЕ»chod ~5:50, zв”ңГӯpad ~18:50
    8:  {6: 0.01, 7: 0.03, 8: 0.07, 9: 0.10, 10: 0.13, 11: 0.15, 12: 0.15, 13: 0.14, 14: 0.11, 15: 0.07, 16: 0.03, 17: 0.01},
    // в”јЕӣв”ңЕҹjen: vв”ңЕ»chod ~6:40, zв”ңГӯpad ~17:30
    9:  {7: 0.02, 8: 0.05, 9: 0.10, 10: 0.14, 11: 0.16, 12: 0.17, 13: 0.16, 14: 0.11, 15: 0.06, 16: 0.03},
    // Listopad: vв”ңЕ»chod ~7:10, zв”ңГӯpad ~16:20
    10: {8: 0.03, 9: 0.08, 10: 0.14, 11: 0.18, 12: 0.20, 13: 0.18, 14: 0.12, 15: 0.06, 16: 0.01},
    // Prosinec: vв”ңЕ»chod ~7:50, zв”ңГӯpad ~16:00 (nejkratв”јГӯв”ңЕҹ den)
    11: {8: 0.02, 9: 0.07, 10: 0.14, 11: 0.19, 12: 0.22, 13: 0.19, 14: 0.12, 15: 0.05}
};
// Vyber kв”јГ–ivku pro aktuв”ңГӯlnв”ңЕҹ mв”ҖЕӨsв”ңЕҹc
var solarCurveWeights = monthlySolarCurves[currentMonth] || monthlySolarCurves[5];

// Spoв”ҖЕ№в”ңЕҹtej celkovou vв”ңГӯhu pro aktivnв”ңЕҹ solв”ңГӯrnв”ңЕҹ hodiny v plв”ңГӯnu
var totalCurveWeight = 0;
for (var cwh = solarStartHour; cwh < solarEndHour; cwh++) {
    totalCurveWeight += solarCurveWeights[cwh] || 0;
}
if (totalCurveWeight === 0) totalCurveWeight = 1; // safety

function getSolarCurveShare(hour) {
    // Vrв”ңГӯtв”ңЕҹ podв”ңЕҹl hodiny na celkovв”ңДҷ vв”ңЕ»robв”ҖЕӨ (0-1) v rв”ңГӯmci aktivnв”ңЕҹch solв”ңГӯrnв”ңЕҹch hodin
    var weight = solarCurveWeights[hour] || 0;
    return weight / totalCurveWeight;
}

function getSolarGainForHour(hour, remainingSolar, solarHours, hFraction) {
    var frac = (hFraction !== undefined) ? hFraction : 1.0;
    var curveShare = getSolarCurveShare(hour);

    // v18.6: Historickв”ңГӯ spotв”јГ–eba per hodina (pв”јГ–esnв”ҖЕӨjв”јГӯв”ңЕҹ neв”јЕј dennв”ңЕҹ prв”јВ»mв”ҖЕӨr)
    var pred = getPredictionForHour(hour);
    var hourlyConsumption = (pred && pred.avgConsumptionKwh > 0)
        ? pred.avgConsumptionKwh
        : (config.daily_consumption_kwh || 20) / 24;

    if (pred && pred.sampleCount >= 3 && pred.avgSolarKwh > 0) {
        // Historickв”ңГӯ data: в”ҖЕ№istв”ңЕ» pв”јГ–ebytek solaru (vв”ңЕ»roba - spotв”јГ–eba)
        var netGain = pred.netSolarGainKwh || 0;
        // v18.5: Sanity check - omezit historickв”ңЕ» gain kв”јГ–ivkou
        if (remainingSolar > 0 && solarHours > 0) {
            var maxFromCurve = remainingSolar * curveShare;
            var maxNetKwh = maxFromCurve - hourlyConsumption;
            if (netGain > maxNetKwh * 2 && maxNetKwh > 0) {
                netGain = maxNetKwh;
            }
        }
        // v18.6: Aplikovat zlomek hodiny
        return (netGain * frac * chargeEfficiency / kapacitaBaterie) * 100;
    }
    // Fallback: rozdв”ҖЕӨlenв”ңЕҹ zbв”ңЕ»vajв”ңЕҹcв”ңЕҹho solaru podle kв”јГ–ivky
    if (solarHours > 0 && remainingSolar > 0) {
        var hourKwh = remainingSolar * curveShare;
        // v18.13: Zв”ңГӯpornв”ңЕ» netKwh = spotв”јГ–eba > vв”ңЕ»roba, baterie dodв”ңГӯ rozdв”ңЕҹl
        var netKwh = hourKwh - hourlyConsumption * frac;
        return (netKwh * frac * chargeEfficiency / kapacitaBaterie) * 100;
    }
    // Plв”ңГӯn v noci pro zв”ңЕҹtв”јГ–ek - pouв”јЕјв”ңЕҹt forecast
    if (forecastZitra > 0 && curveShare > 0) {
        var hourKwhForecast = forecastZitra * curveShare;
        // v18.13: Zв”ңГӯpornв”ңЕ» = spotв”јГ–eba > forecast vв”ңЕ»roba
        var netKwhForecast = hourKwhForecast - hourlyConsumption * frac;
        return (netKwhForecast * frac * chargeEfficiency / kapacitaBaterie) * 100;
    }
    return 0;
}

// v17: Maintenance charge - 20 dnв”ңЕҹ, pouze v zimв”ҖЕӨ (в”јГ–в”ңЕҹjen-bв”јГ–ezen)
var lastFullCharge = global.get("fve_last_full_charge") || null;
if (!lastFullCharge) {
    global.set("fve_last_full_charge", new Date().toISOString());
    lastFullCharge = global.get("fve_last_full_charge");
}
var daysSinceFullCharge = lastFullCharge
    ? Math.floor((Date.now() - new Date(lastFullCharge).getTime()) / (1000 * 60 * 60 * 24))
    : 999;
if (currentSoc >= 99) {
    global.set("fve_last_full_charge", new Date().toISOString());
}

var now = new Date();
var currentHour = now.getHours();
var currentMinute = now.getMinutes();
var firstHourFraction = (60 - currentMinute) / 60; // v18.6: zlomek zbв”ңЕ»vajв”ңЕҹcв”ңЕҹ prvnв”ңЕҹ hodiny
var currentMonth = now.getMonth() + 1; // 1-12
var isWinter = (currentMonth >= 10 || currentMonth <= 3); // в”јГ–в”ңЕҹjen-bв”јГ–ezen

// === POMOCNв”ңГј FUNKCE: NAJDI CENOVв”ңЕҒ Zв”ңГјZNAM ===
function findPriceEntry(hour, offset) {
    var isNextDay = (currentHour + (offset || 0)) >= 24;
    var preferDay = isNextDay ? "hoursTomorrow" : "hoursToday";
    var otherDay = isNextDay ? "hoursToday" : "hoursTomorrow";

    for (var i = 0; i < prices.length; i++) {
        if (prices[i].day === preferDay && prices[i].hour === hour && prices[i].minute === 0) {
            return { entry: prices[i], method: "exact_" + preferDay };
        }
    }
    for (var j = 0; j < prices.length; j++) {
        if (prices[j].day === preferDay && prices[j].hour === hour) {
            return { entry: prices[j], method: "dayHour_" + preferDay };
        }
    }
    for (var k = 0; k < prices.length; k++) {
        if (prices[k].day === otherDay && prices[k].hour === hour && prices[k].minute === 0) {
            return { entry: prices[k], method: "exact_" + otherDay };
        }
    }
    for (var m = 0; m < prices.length; m++) {
        if (prices[m].day === otherDay && prices[m].hour === hour) {
            return { entry: prices[m], method: "dayHour_" + otherDay };
        }
    }
    for (var n = 0; n < prices.length; n++) {
        if (prices[n].hour === hour) {
            return { entry: prices[n], method: "any_" + (prices[n].day || "noday") };
        }
    }
    return { entry: null, method: "none" };
}

// === KROK 1: CENOVв”ңГј MAPA HORIZONTU ===
var hourPrices = [];
var debugMatches = [];
for (var hi = 0; hi < horizont; hi++) {
    var hh = (currentHour + hi) % 24;
    var found = findPriceEntry(hh, hi);
    var entry = found.entry;
    hourPrices.push({
        offset: hi,
        hour: hh,
        buy: entry ? (parseFloat(entry.priceCZKhourBuy) || 0) : 0,
        sell: entry ? (parseFloat(entry.priceCZKhourProd) || 0) : 0,
        levelBuy: entry ? (entry.levelCheapestHourBuy || 5) : 5,
        levelSell: entry ? (entry.levelMostExpensiveHourProd || 5) : 5
    });
    debugMatches.push({
        offset: hi, hour: hh, method: found.method,
        day: entry ? entry.day : null, min: entry ? entry.minute : null,
        buy: entry ? entry.priceCZKhourBuy : null, lvl: entry ? entry.levelCheapestHourBuy : null
    });
}

// === KROK 2: IDENTIFIKUJ SOLв”ңГјRNв”ңЕ№ HODINY (potв”јГ–ebuji je dв”јГ–в”ңЕҹve pro vв”ңЕ»poв”ҖЕ№et nabв”ңЕҹjenв”ңЕҹ) ===
var solarOffsets = {};
var solarHoursCount = 0;
for (var sh = 0; sh < horizont; sh++) {
    var shh = (currentHour + sh) % 24;
    if (shh >= solarStartHour && shh < solarEndHour) {
        solarOffsets[sh] = true;
        solarHoursCount++;
    }
}

// === KROK 3: NAJDI DRAHв”ңГ« HODINY Pв”јЕӣED SOLAREM ===
// Klв”ңЕҹв”ҖЕ№ovв”ңЕ» vв”ңЕ»poв”ҖЕ№et: kolik drahв”ңЕ»ch hodin je Pв”јЕӣED dalв”јГӯв”ңЕҹm solв”ңГӯrnв”ңЕҹm oknem?
// Tyto hodiny MUSв”ңЕ№ pokrв”ңЕ»t baterie (vybв”ңЕҹjenв”ңЕҹm)
var expensiveBeforeSolar = [];
var firstSolarOffset = horizont;
for (var fso = 0; fso < horizont; fso++) {
    if (solarOffsets[fso]) {
        firstSolarOffset = fso;
        break;
    }
}

for (var eo = 0; eo < hourPrices.length; eo++) {
    var hp = hourPrices[eo];
    var isSolarHour = solarOffsets[eo];
    if (hp.levelBuy >= PRAH_DRAHA && !isSolarHour && eo < firstSolarOffset) {
        expensiveBeforeSolar.push(hp);
    }
}

// Vв”јГӯechny drahв”ңДҷ hodiny (pro finanв”ҖЕ№nв”ңЕҹ kalkulaci)
var allExpensiveHours = hourPrices.filter(function(hp) {
    return hp.levelBuy >= PRAH_DRAHA && !solarOffsets[hp.offset];
});
var avgExpensivePrice = 0;
if (allExpensiveHours.length > 0) {
    var sum = 0;
    for (var ei = 0; ei < allExpensiveHours.length; ei++) {
        sum += allExpensiveHours[ei].buy;
    }
    avgExpensivePrice = sum / allExpensiveHours.length;
}

// === KROK 4: KOLIK ENERGIE POTв”јЕӣEBUJI ZE Sв”ңЕ№Tв”ҖГң? ===
// v17: Pв”јЕӣESNв”ңЕҒ vв”ңЕ»poв”ҖЕ№et - nabв”ңЕҹjet JEN pokud currentSoc nestaв”ҖЕ№в”ңЕҹ
//
// Logika:
// 1. Spoв”ҖЕ№в”ңЕҹtej reв”ңГӯlnв”ңЕ» drain do solaru = drahв”ңДҷ hodiny pв”јГ–ed solarem в”ңЕҡ socDropNormal
// 2. SOC po vybв”ңЕҹjenв”ңЕҹ = currentSoc - drain
// 3. Pokud SOC po vybв”ңЕҹjenв”ңЕҹ >= minSoc + safety Г”ДҮДә NENABв”ңЕ№JET (solв”ңГӯr dobije)
// 4. Pokud SOC po vybв”ңЕҹjenв”ңЕҹ < minSoc + safety Г”ДҮДә nabв”ңЕҹt JEN deficit
//
// Pв”јГ–в”ңЕҹklad z problemy.txt:
//   currentSoc=42%, drahв”ңДҷ hodiny pв”јГ–ed solarem=3 (06,07,08), drain=15%
//   SOC po vybв”ңЕҹjenв”ңЕҹ = 42% - 15% = 27%
//   minSoc + safety = 20% + 5% = 25%
//   27% > 25% Г”ДҮДә NENABв”ңЕ№JET Г”ЕҘГҙ

var drainBeforeSolarPct = expensiveBeforeSolar.length * socDropNormal;
var socAfterDrain = currentSoc - drainBeforeSolarPct;

// Safety margin zв”ңГӯvisв”ңЕҹ na solв”ңГӯrnв”ңЕҹ pв”јГ–edpovв”ҖЕӨdi
var safetyMargin = 5;
if (forecastZitra < dailyConsumptionKwh * 0.3) {
    safetyMargin = 10; // в”јГӯpatnв”ңГӯ pв”јГ–edpovв”ҖЕӨв”ҖДҶ
} else if (forecastZitra < dailyConsumptionKwh * 0.5) {
    safetyMargin = 7; // stв”јГ–ednв”ңЕҹ pв”јГ–edpovв”ҖЕӨв”ҖДҶ
}

var minRequiredSoc = minSoc + safetyMargin;
var gridChargeNeeded = 0;
var targetSocFromGrid = currentSoc; // default: nenabв”ңЕҹjet

// Nabв”ңЕҹjet ze sв”ңЕҹtв”ҖЕӨ JEN pokud SOC po vybв”ңЕҹjenв”ңЕҹ drahв”ңЕ»ch hodin nestaв”ҖЕ№в”ңЕҹ
if (socAfterDrain < minRequiredSoc) {
    // Deficit: kolik % chybв”ңЕҹ?
    var deficitPct = minRequiredSoc - socAfterDrain;
    // Nabв”ңЕҹt tak, aby po vybв”ңЕҹjenв”ңЕҹ drahв”ңЕ»ch hodin zв”јВ»stalo minRequiredSoc
    targetSocFromGrid = Math.min(maxDailySoc, currentSoc + Math.ceil(deficitPct));
    gridChargeNeeded = Math.max(0, ((targetSocFromGrid - currentSoc) / 100) * kapacitaBaterie / chargeEfficiency);
}

// Pokud target je moc blв”ңЕҹzko currentSoc, nenabв”ңЕҹjet
if (targetSocFromGrid <= currentSoc + 3) {
    gridChargeNeeded = 0;
    targetSocFromGrid = currentSoc;
}

// v17: Maintenance charge - 20 dnв”ңЕҹ, pouze v zimв”ҖЕӨ
var maintenanceCharge = false;
if (isWinter && daysSinceFullCharge >= 20 && targetSocFromGrid < 100) {
    targetSocFromGrid = 100;
    gridChargeNeeded = ((100 - currentSoc) / 100) * kapacitaBaterie / chargeEfficiency;
    maintenanceCharge = true;
}

// === KROK 4b: FINANв”ҖГ®Nв”ңЕ№ SMYSLUPLNOST NABв”ңЕ№JENв”ңЕ№ ===
var viableChargingHours = [];
if (gridChargeNeeded > 0) {
    for (var vi = 0; vi < hourPrices.length; vi++) {
        var chp = hourPrices[vi];
        if (chp.levelBuy > PRAH_LEVNA) continue;
        if (!solarOffsets[chp.offset]) { // nenabв”ңЕҹjet v solв”ңГӯrnв”ңЕҹch hodinв”ңГӯch ze sв”ңЕҹtв”ҖЕӨ
            var effectiveCost = chp.buy / roundTripEfficiency + amortizace;
            if (effectiveCost < avgExpensivePrice || avgExpensivePrice === 0 || maintenanceCharge) {
                viableChargingHours.push(chp);
            }
        }
    }
    viableChargingHours.sort(function(a, b) { return a.buy - b.buy; });
}

var hoursNeeded = Math.ceil(gridChargeNeeded / chargeRateKwh);

// === KROK 5: Pв”јЕӣIв”јЕӣAв”ҖГ„ NABв”ңЕ№JECв”ңЕ№ HODINY ===
var chargingOffsets = {};
var assignedHours = 0;

if (viableChargingHours.length > 0) {
    for (var ci = 0; ci < viableChargingHours.length && assignedHours < hoursNeeded; ci++) {
        chargingOffsets[viableChargingHours[ci].offset] = true;
        assignedHours++;
    }
}

// Fallback: pokud nestaв”ҖЕ№в”ңЕҹ viable hours, hledej dalв”јГӯв”ңЕҹ levnв”ңДҷ
if (assignedHours < hoursNeeded) {
    var cheapestAvail = hourPrices.slice().filter(function(hp) {
        return !chargingOffsets[hp.offset] && hp.levelBuy <= PRAH_LEVNA && !solarOffsets[hp.offset];
    });
    cheapestAvail.sort(function(a, b) { return a.buy - b.buy; });
    for (var ca = 0; ca < cheapestAvail.length && assignedHours < hoursNeeded; ca++) {
        chargingOffsets[cheapestAvail[ca].offset] = true;
        assignedHours++;
    }
}

// Maintenance: pokud stв”ңГӯle nestaв”ҖЕ№в”ңЕҹ, pouв”јЕјij i draв”јЕјв”јГӯв”ңЕҹ hodiny
if (maintenanceCharge && assignedHours < hoursNeeded) {
    var remaining = hourPrices.filter(function(hp) {
        return !chargingOffsets[hp.offset] && hp.levelBuy < PRAH_DRAHA && !solarOffsets[hp.offset];
    });
    remaining.sort(function(a, b) { return a.buy - b.buy; });
    for (var ri = 0; ri < remaining.length && assignedHours < hoursNeeded; ri++) {
        chargingOffsets[remaining[ri].offset] = true;
        assignedHours++;
    }
}

// Upravit target pokud se nepodaв”јГ–ilo pв”јГ–iв”јГ–adit dost hodin
if (assignedHours < hoursNeeded && !maintenanceCharge) {
    var actualChargeKwh = assignedHours * chargeRateKwh * chargeEfficiency;
    targetSocFromGrid = Math.min(targetSocFromGrid,
        currentSoc + Math.round(actualChargeKwh / kapacitaBaterie * 100));
    gridChargeNeeded = actualChargeKwh;
}

// Odstraв”јЕӮ solв”ңГӯrnв”ңЕҹ hodiny z chargingOffsets (pro jistotu)
for (var cso in chargingOffsets) {
    if (solarOffsets[cso]) {
        delete chargingOffsets[cso];
    }
}

// === KROK 6: SOLв”ңГјRNв”ңЕ№ SOC GAIN ===
var solarSocGainTotal = 0;
if (solarHoursCount > 0 && remainingSolarKwh > 0) {
    solarSocGainTotal = (remainingSolarKwh * chargeEfficiency / kapacitaBaterie) * 100;
}

// === KROK 7: DYNAMICKв”ңЕҒ PRв”ңГјH VYBв”ңЕ№JENв”ңЕ№ ===
var dischargeCandidate = [];
for (var dc = 0; dc < hourPrices.length; dc++) {
    if (!solarOffsets[dc] && !chargingOffsets[dc]) {
        dischargeCandidate.push({
            offset: dc,
            hour: hourPrices[dc].hour,
            levelBuy: hourPrices[dc].levelBuy,
            buy: hourPrices[dc].buy
        });
    }
}

dischargeCandidate.sort(function(a, b) {
    if (b.levelBuy !== a.levelBuy) return b.levelBuy - a.levelBuy;
    return b.buy - a.buy;
});

var availableBatteryKwh = Math.max(0, (currentSoc - minSoc) / 100 * kapacitaBaterie * dischargeEfficiency);
var energyBudgetKwh = availableBatteryKwh;

var dischargeOffsets = {};
var effectiveThreshold = PRAH_DRAHA;
var usedEnergyKwh = 0;
var dischargeDebug = [];

for (var di = 0; di < dischargeCandidate.length; di++) {
    var cand = dischargeCandidate[di];
    var energyForThisHour = socDropNormal / 100 * kapacitaBaterie;

    if (usedEnergyKwh + energyForThisHour <= energyBudgetKwh) {
        dischargeOffsets[cand.offset] = true;
        usedEnergyKwh += energyForThisHour;
        effectiveThreshold = Math.min(effectiveThreshold, cand.levelBuy);
        dischargeDebug.push({
            offset: cand.offset, hour: cand.hour, level: cand.levelBuy,
            price: cand.buy, action: "NORMAL",
            usedKwh: Math.round(usedEnergyKwh * 10) / 10,
            budgetKwh: Math.round(energyBudgetKwh * 10) / 10
        });
    } else if (cand.levelBuy >= PRAH_DRAHA && usedEnergyKwh < energyBudgetKwh) {
        // v18.17: Budget nestaв”ҖЕ№в”ңЕҹ na celou hodinu, ale levelBuy je drahв”ңЕ»
        // Pв”јГ–idв”ңГӯme hodinu - baterie se vybije co mв”јВ»в”јЕјe (aв”јЕј na minSoc)
        dischargeOffsets[cand.offset] = true;
        usedEnergyKwh = energyBudgetKwh; // vyв”ҖЕ№erpв”ңГӯme zbytek budgetu
        effectiveThreshold = Math.min(effectiveThreshold, cand.levelBuy);
        dischargeDebug.push({
            offset: cand.offset, hour: cand.hour, level: cand.levelBuy,
            price: cand.buy, action: "NORMAL (partial, budget limit)",
            usedKwh: Math.round(usedEnergyKwh * 10) / 10,
            budgetKwh: Math.round(energyBudgetKwh * 10) / 10
        });
    } else {
        dischargeDebug.push({
            offset: cand.offset, hour: cand.hour, level: cand.levelBuy,
            price: cand.buy, action: "SETRIT (budget exceeded)",
            usedKwh: Math.round(usedEnergyKwh * 10) / 10,
            budgetKwh: Math.round(energyBudgetKwh * 10) / 10
        });
    }
}

// v18.18b: Flag - existujв”ңЕҹ drahв”ңДҷ hodiny bez budgetu na vybв”ңЕҹjenв”ңЕҹ?
var budgetExhausted = false;
for (var be = 0; be < dischargeCandidate.length; be++) {
    if (!dischargeOffsets[dischargeCandidate[be].offset] && dischargeCandidate[be].levelBuy >= PRAH_DRAHA) {
        budgetExhausted = true;
        break;
    }
}

// === KROK 8: Vв”ңЕҒPOв”ҖГ®ET Mв”ңГҙDU PRO KAв”јЕ»DOU HODINU ===
function calculateModeForHour(offset, priceData, simulatedSoc, hFraction) {
    var frac = (hFraction !== undefined) ? hFraction : 1.0;
    if (manualMod !== "auto") {
        return { mode: manualMod, reason: "Manuв”ңГӯlnв”ңЕҹ mв”ңв”Ӯd" };
    }

    var priceSell = priceData.sell;
    var levelSell = priceData.levelSell;
    var levelBuy = priceData.levelBuy;

    // PRIORITA 0: Zв”ңГӯpornв”ңГӯ prodejnв”ңЕҹ cena
    if (priceSell <= 0) {
        return { mode: MODY.ZAKAZ_PRETOKU, reason: "Zв”ңГӯpornв”ңГӯ prodejnв”ңЕҹ cena" };
    }

    // PRIORITA 1: Nabв”ңЕҹjenв”ңЕҹ ze sв”ңЕҹtв”ҖЕӨ
    if (chargingOffsets[offset] && simulatedSoc < targetSocFromGrid) {
        return {
            mode: MODY.NABIJET_ZE_SITE,
            reason: "Nabв”ңЕҹjenв”ңЕҹ na cв”ңЕҹl " + Math.round(targetSocFromGrid) + "% (nynв”ңЕҹ " + Math.round(simulatedSoc) + "%)"
        };
    }

    // PRIORITA 2: Prodej z baterie pв”јГ–i vв”ңЕ»hodnв”ңДҷ cenв”ҖЕӨ
    if (prodejZBaterieEnabled && levelSell <= 2 && simulatedSoc > minSoc + 20) {
        var avgChargeCost = 0;
        if (viableChargingHours.length > 0) {
            var s = 0;
            for (var ac = 0; ac < viableChargingHours.length; ac++) {
                s += viableChargingHours[ac].buy;
            }
            avgChargeCost = s / viableChargingHours.length;
        }
        var revenuePerKwh = priceSell * dischargeEfficiency;
        var costPerKwh = avgChargeCost / roundTripEfficiency + amortizace;
        if (revenuePerKwh > costPerKwh) {
            var dischRateKwh = maxFeedInW / 1000;
            var socAfter = Math.max(minSoc,
                simulatedSoc - (dischRateKwh / dischargeEfficiency / kapacitaBaterie * 100));
            return {
                mode: MODY.PRODAVAT,
                reason: "Prodej, SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(socAfter) + "%"
            };
        }
    }

    // PRIORITA 3: Ochrana baterie - pв”јГ–в”ңЕҹliв”јГӯ nв”ңЕҹzkв”ңЕ» SOC
    if (simulatedSoc <= minSoc) {
        return {
            mode: MODY.SETRIT,
            reason: "Ochrana baterie (SOC " + Math.round(simulatedSoc) + "% Г”Г«Д„ " + minSoc + "%)"
        };
    }

    // PRIORITA 4: Solв”ңГӯrnв”ңЕҹ hodiny - v18.18: в”јГЎETв”јЕӣIT pв”јГ–i nв”ңЕҹzkв”ңДҷm zisku, NORMAL pв”јГ–i vysokв”ңДҷm
    if (solarOffsets[offset]) {
        var planHourForSolar = (currentHour + offset) % 24;
        var solarGainPct = getSolarGainForHour(planHourForSolar, remainingSolarKwh, solarHoursCount, frac);
        var solarGainEst = Math.round(solarGainPct * 10) / 10;
        var expectedSocSolar = Math.min(100, simulatedSoc + solarGainEst);

        // v18.18: Pokud solв”ңГӯrnв”ңЕҹ zisk vв”ңЕ»raznв”ҖЕӨ nabв”ңЕҹjв”ңЕҹ baterii, vв”јЕјdy NORMAL
        if (solarGainEst > socDropNormal) {
            return {
                mode: MODY.NORMAL,
                reason: "Solв”ңГӯrnв”ңЕҹ hodina, SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(expectedSocSolar) + "%"
            };
        }

        // Nв”ңЕҹzkв”ңЕ» solв”ңГӯrnв”ңЕҹ zisk - rozhodnutв”ңЕҹ dle ceny (viz v18.19 vв”ңЕ»в”јГӯe)

        // v18.19: Drahв”ңГӯ hodina (levelBuy >= PRAH_DRAHA) - vв”јЕјdy NORMAL (vybв”ңЕҹjet)
        if (levelBuy >= PRAH_DRAHA && simulatedSoc > minSoc) {
            return {
                mode: MODY.NORMAL,
                reason: "Solв”ңГӯrnв”ңЕҹ+drahв”ңГӯ (Lv" + levelBuy + "Г”Г«Д…" + PRAH_DRAHA + "), SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(expectedSocSolar) + "%"
            };
        }

        // Nв”ңЕҹzkв”ңЕ» zisk a levnв”ңГӯ hodina - в”јГЎETв”јЕӣIT pouze pokud budget nestaв”ҖЕ№в”ңЕҹ
        if (budgetExhausted) {
            return {
                mode: MODY.SETRIT,
                reason: "Solв”ңГӯrnв”ңЕҹ (nв”ңЕҹzkв”ңЕ» zisk +" + solarGainEst + "%), в”јГӯetв”јГ–в”ңЕҹm na draв”јЕјв”јГӯв”ңЕҹ hodiny, SOC " + Math.round(simulatedSoc) + "%"
            };
        }
        // Budget staв”ҖЕ№в”ңЕҹ - NORMAL
        return {
            mode: MODY.NORMAL,
            reason: "Solв”ңГӯrnв”ңЕҹ hodina, SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(expectedSocSolar) + "%"
        };
    }

    // PRIORITA 5: NORMAL pro hodiny vybranв”ңДҷ dynamickв”ңЕ»m prahem (vybв”ңЕҹjenв”ңЕҹ)
    if (dischargeOffsets[offset] && simulatedSoc > minSoc) {
        var expectedSocDischarge = Math.max(minSoc, simulatedSoc - socDropNormal * frac);
        var priceInfo = levelBuy >= PRAH_DRAHA ? "drahв”ңГӯ" : (levelBuy <= PRAH_LEVNA ? "levnв”ңГӯ" : "stв”јГ–ednв”ңЕҹ");
        return {
            mode: MODY.NORMAL,
            reason: priceInfo + " (Lv" + levelBuy + "Г”Г«Д…eff" + effectiveThreshold + "), vybв”ңЕҹjenв”ңЕҹ SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(expectedSocDischarge) + "%"
        };
    }

    // PRIORITA 5b: v18.19 - Drahв”ңДҷ hodiny Vв”јЕ»DY vybв”ңЕҹjet (i bez budgetu)
    if (levelBuy >= PRAH_DRAHA && simulatedSoc > minSoc) {
        var expectedSocForced = Math.max(minSoc, simulatedSoc - socDropNormal * frac);
        return {
            mode: MODY.NORMAL,
            reason: "drahв”ңГӯ (Lv" + levelBuy + "Г”Г«Д…" + PRAH_DRAHA + "), vybв”ңЕҹjenв”ңЕҹ SOC " + Math.round(simulatedSoc) + "% Г”ДҮДә ~" + Math.round(expectedSocForced) + "%"
        };
    }

    // PRIORITA 6: в”јГЎETв”јЕӣIT (vв”ңЕ»chozв”ңЕҹ mв”ңв”Ӯd) - pouze levnв”ңДҷ hodiny (levelBuy < PRAH_DRAHA)
    return {
        mode: MODY.SETRIT,
        reason: "в”јГЎetв”јГ–в”ңЕҹm (Lv" + levelBuy + "<" + PRAH_DRAHA + "), SOC " + Math.round(simulatedSoc) + "%"
    };
}

// === SIMULACE SOC ===
function simulateSocChange(mode, hour, soc, hFraction, chargeTarget) {
    var frac = (hFraction !== undefined) ? hFraction : 1.0;
    var isSolar = hour >= solarStartHour && hour < solarEndHour;
    switch (mode) {
        case MODY.NABIJET_ZE_SITE:
            var maxChargeSoc = (chargeTarget && chargeTarget > 0) ? chargeTarget : 100;
            return Math.min(maxChargeSoc, soc + (chargeRateKwh * frac * chargeEfficiency / kapacitaBaterie * 100));
        case MODY.PRODAVAT:
            var dischRateKwh = maxFeedInW / 1000;
            return Math.max(minSoc, soc - (dischRateKwh * frac / dischargeEfficiency / kapacitaBaterie * 100));
        case MODY.SETRIT:
            return soc;
        case MODY.ZAKAZ_PRETOKU:
            return Math.max(minSoc, soc - socDropSetrit * frac);
        case MODY.NORMAL:
            if (isSolar) {
                var solarGainSim = getSolarGainForHour(hour, remainingSolarKwh, solarHoursCount, frac);
                // v18.13: Zв”ңГӯpornв”ңЕ» gain = spotв”јГ–eba > vв”ңЕ»roba, SOC klesв”ңГӯ
                return Math.min(100, Math.max(minSoc, soc + solarGainSim));
            }
            return Math.max(minSoc, soc - socDropNormal * frac);
        default:
            return soc;
    }
}

// === GENEROVв”ңГјNв”ңЕ№ PLв”ңГјNU ===
var modeNamesCZ = {
    normal: "Normв”ңГӯlnв”ңЕҹ provoz",
    setrit: "в”јГЎetв”јГ–it baterii",
    nabijet_ze_site: "Nabв”ңЕҹjet ze sв”ңЕҹtв”ҖЕӨ",
    prodavat: "Prodв”ңГӯvat do sв”ңЕҹtв”ҖЕӨ",
    zakaz_pretoku: "Zв”ңГӯkaz pв”јГ–etokв”јВ»"
};

var plan = [];
var simulatedSoc = currentSoc;

for (var pi = 0; pi < horizont; pi++) {
    var planHour = (currentHour + pi) % 24;
    var isNextDay = (currentHour + pi) >= 24;
    var priceData = hourPrices[pi];
    var hFrac = (pi === 0) ? firstHourFraction : 1.0;
    var result = calculateModeForHour(pi, priceData, simulatedSoc, hFrac);
    simulatedSoc = simulateSocChange(result.mode, planHour, simulatedSoc, hFrac, targetSocFromGrid);
    plan.push({
        hour: planHour,
        offset: pi,
        mode: result.mode,
        modeCZ: modeNamesCZ[result.mode] || result.mode,
        reason: result.reason,
        priceLevel: priceData.levelBuy,
        priceBuy: priceData.buy,
        priceSell: priceData.sell,
        simulatedSoc: Math.round(simulatedSoc),
        isNextDay: isNextDay,
        isChargingHour: chargingOffsets[pi] || false,
        isSolarHour: solarOffsets[pi] || false,
        isDischargeHour: dischargeOffsets[pi] || false
    });
}

// === LOGOVв”ңГјNв”ңЕ№ ===
var countSetrit = 0, countNormal = 0, countNabijet = 0;
for (var cs = 0; cs < plan.length; cs++) {
    if (plan[cs].mode === MODY.SETRIT) countSetrit++;
    else if (plan[cs].mode === MODY.NORMAL) countNormal++;
    else if (plan[cs].mode === MODY.NABIJET_ZE_SITE) countNabijet++;
}

// === Vв”ңЕҒSTUP ===
var currentMode = plan.length > 0 ? plan[0].mode : MODY.NORMAL;
var currentReason = plan.length > 0 ? plan[0].reason : "";

msg.payload = {
    currentMode: currentMode,
    currentReason: currentReason,
    currentHour: currentHour,
    plan: plan,
    dischargeDebug: dischargeDebug,
    config: { 
        prah_levna: PRAH_LEVNA,
        prah_draha: PRAH_DRAHA,
        effective_threshold: effectiveThreshold,
        solarStartHour: solarStartHour,
        solarEndHour: solarEndHour
    },
    proteus: {
        firstSolarOffset: firstSolarOffset,
        dischargeHoursCount: Object.keys(dischargeOffsets).length,
        solarHoursCount: Object.keys(solarOffsets).length,
        energyBudgetKwh: Math.round(energyBudgetKwh * 10) / 10,
        usedEnergyKwh: Math.round(usedEnergyKwh * 10) / 10,
        effectiveThreshold: effectiveThreshold,
        peakSoc: Math.round(currentSoc + solarSocGainTotal),
        totalSolarAvailable: Math.round((remainingSolarKwh + forecastZitra) * 10) / 10,
        forecastZitra: forecastZitra,
        drainBeforeSolarPct: drainBeforeSolarPct,
        socAfterDrain: Math.round(socAfterDrain),
        minRequiredSoc: minRequiredSoc
    },
    smartCharging: {
        targetSocFromGrid: Math.round(targetSocFromGrid),
        gridChargeNeeded: Math.round(gridChargeNeeded * 10) / 10,
        hoursNeeded: hoursNeeded,
        assignedHours: assignedHours,
        viableHoursAvailable: viableChargingHours.length,
        remainingSolar: Math.round(remainingSolarKwh * 10) / 10,
        roundTripEfficiency: Math.round(roundTripEfficiency * 100),
        amortizace: amortizace,
        daysToFullCharge: daysSinceFullCharge,
        maintenanceCharge: maintenanceCharge,
        isWinter: isWinter,
        chargingReason: gridChargeNeeded > 0 
            ? (maintenanceCharge ? "maintenance (20d)" : "deficit " + Math.round(minRequiredSoc - socAfterDrain) + "%")
            : "nepotв”јГ–eba (SOC " + Math.round(socAfterDrain) + "% > min " + minRequiredSoc + "%)"
    },
    planSummary: {
        setritHours: countSetrit,
        normalHours: countNormal,
        nabijetHours: countNabijet
    },
    status: {
        soc: currentSoc,
        remainingSolar: remainingSolarKwh,
        forecastZitra: forecastZitra,
        forecastDnes: forecast.dnes || 0,
        prodejEnabled: prodejZBaterieEnabled,
        blokaceVybijeni: blokaceVybijeni,
        blokaceText: blokaceText
    },
    generatedAt: now.toISOString()
};

var modeColors = {
    normal: "green",
    setrit: "yellow",
    nabijet_ze_site: "blue",
    prodavat: "red",
    zakaz_pretoku: "purple"
};
node.status({
    fill: modeColors[currentMode] || "grey",
    shape: "dot",
    text: "v18 " + currentMode
        + " | в”јГЎ:" + countSetrit + " N:" + countNormal + " Nab:" + countNabijet
        + " | effThr:" + effectiveThreshold
        + " | SOC:" + currentSoc + "% drn:" + drainBeforeSolarPct + "% Г”ДҮДә" + Math.round(socAfterDrain) + "%"
        + " | Г”ЕӣГҮ" + solarStartHour + "-" + solarEndHour + "h"
        + (gridChargeNeeded > 0 ? " | Г”ГңГӯ" + Math.round(targetSocFromGrid) + "%" : "")
});

return msg;

global.set("fve_plan", msg.payload);
global.set("fve_current_mode", msg.payload.currentMode);

msg.ha_update = {
    state: msg.payload.currentMode,
    attributes: {
        current_mode: msg.payload.currentMode,
        current_reason: msg.payload.currentReason,
        current_hour: msg.payload.currentHour,
        plan: msg.payload.plan,
        soc: msg.payload.status.soc,
        forecast_dnes: msg.payload.status.forecastDnes,
        forecast_zitra: msg.payload.status.forecastZitra,
        last_update: msg.payload.generatedAt,
        debug: msg.payload.debug || {},
        blokace_text: msg.payload.status.blokaceText || "NE"
    }
};

return msg;

var planData = msg.payload || {};
var currentMode = planData.currentMode || "normal";
var currentHour = planData.currentHour || new Date().getHours();
var planArray = planData.plan || [];

node.status({fill:"green", shape:"dot", text: "Mв”ңв”Ӯd: " + currentMode + ", hodina: " + currentHour});

msg.payload = JSON.stringify({
    current_mode: currentMode,
    current_reason: planData.currentReason || "",
    current_hour: currentHour,
    plan: planArray,
    soc: planData.status ? planData.status.soc : null,
    forecast_dnes: planData.status ? planData.status.forecastDnes : null,
    forecast_zitra: planData.status ? planData.status.forecastZitra : null,
    debug: planData.debug || "",
    blokace_text: planData.status ? (planData.status.blokaceText || "NE") : "NE",
    last_update: new Date().toISOString()
}, null, 2);

return msg;

var config = global.get("fve_config") || {};
var plan = global.get("fve_plan") || {};
// FIX: Read planned mode from plan object (immutable, set by planner only)
// Previously read from fve_current_mode which was overwritten by override logic
var planMode = (plan && plan.currentMode) ? plan.currentMode : "normal";
var manualMod = config.manual_mod || "auto";

var currentMode = planMode;
if (manualMod !== "auto") {
    currentMode = manualMod;
}

var wasEnabled = flow.get("automatizace_was_enabled") || false;
if (config.automatizace_enabled === false) {
    if (wasEnabled) {
        // PrГЎvДӣ vypnuta automatizace вҶ’ pЕҷejdi do NORMAL (safe state) JEDNOU
        flow.set("automatizace_was_enabled", false);
        flow.set("auto_off_normal_sent", false);  // reset flag pro pЕҷГӯЕЎtГӯ cyklus
        global.set("fve_current_mode", "normal");
        msg.currentMode = "normal";
        msg.autoNabijeniAktivni = false;
        msg.cerpadloTopi = global.get("cerpadlo_topi") || false;
        msg.saunaAktivni = global.get("sauna_aktivni") || false;
        node.status({fill:"yellow", shape:"dot", text:"AUTO OFF вҶ’ NORMAL mГіd (reset Victronu)"});
        return msg;  // POЕ LI jednou do NORMAL mГіdu
    }
    var normalSent = flow.get("auto_off_normal_sent") || false;
    if (!normalSent) {
        // Automatizace zЕҜstГЎvГЎ vypnuta, ale jeЕЎtДӣ jsme neposlali NORMAL вҶ’ poЕЎli jednou
        flow.set("auto_off_normal_sent", true);
        global.set("fve_current_mode", "normal");
        msg.currentMode = "normal";
        msg.autoNabijeniAktivni = false;
        msg.cerpadloTopi = global.get("cerpadlo_topi") || false;
        msg.saunaAktivni = global.get("sauna_aktivni") || false;
        node.status({fill:"grey", shape:"ring", text:"Automatizace vypnuta (NORMAL reset)"});
        return msg;
    }
    node.status({fill:"grey", shape:"ring", text:"Automatizace vypnuta"});
    return null;
}
flow.set("automatizace_was_enabled", true);
flow.set("auto_off_normal_sent", false);  // reset pЕҷi zapnutГӯ

var autoNabijeni = global.get("auto_nabijeni_aktivni") || false;

// Grid Lost ochrana
var gridLostState = global.get("homeassistant.homeAssistant.states['sensor.grid_lost_ciselny']") || {};
var gridLost = parseInt(gridLostState.state || "0") >= 2;
var cerpadloTopi = global.get("cerpadlo_topi") || false;
var saunaAktivni = global.get("sauna_aktivni") || false;

// FIX: Removed override normal->setrit when heat pump/car active.
// Root cause of battery charging in Normal mode:
//   Override switched to Setrit which set max_discharge_power=0 and
//   scheduled_soc=currentSoc, causing solar->battery and grid->consumption.
// The planner already assigns correct modes. Individual modes (e.g. Nabijet)
// already adjust power_set_point for high-priority consumers.

// Update display mode
// Grid Lost: pв”јГ–epnout na в”јГӯetв”јГ–it (в”јЕјв”ңГӯdnв”ңДҷ nabв”ңЕҹjenв”ңЕҹ ze sв”ңЕҹtв”ҖЕӨ, baterie se nevybв”ңЕҹjв”ңЕҹ)
if (gridLost && currentMode === "nabijet_ze_site") {
    currentMode = "setrit";
    node.status({fill:"red", shape:"dot", text:"GRID LOST Г”ДҮДә в”јГЎetв”јГ–it (blokace nabв”ңЕҹjenв”ңЕҹ)"});
}
global.set("fve_current_mode", currentMode);

// v18.2: Blokace text pro dashboard
var blokaceItems = [];
if (gridLost) blokaceItems.push("GRID LOST");
if (cerpadloTopi) blokaceItems.push("topenв”ңЕҹ");
if (autoNabijeni) blokaceItems.push("auto");
if (saunaAktivni) blokaceItems.push("sauna");
var blokaceText = blokaceItems.length > 0 ? "ANO - " + blokaceItems.join(", ") : "NE";

// Update blokaceText in global fve_plan for real-time file updates
var currentPlan = global.get("fve_plan") || {};
if (!currentPlan.status) currentPlan.status = {};
currentPlan.status.blokaceText = blokaceText;
global.set("fve_plan", currentPlan);

msg.blokaceText = blokaceText;
msg.autoNabijeniAktivni = autoNabijeni;
msg.cerpadloTopi = cerpadloTopi;
msg.gridLost = gridLost;
msg.saunaAktivni = saunaAktivni;
msg.config = config;
msg.plan = plan;

var modeSource = manualMod !== "auto" ? "(manualni)" : "(auto)";
var infoText = "";
if (gridLost) infoText += " | Г”ГңГӯGRID LOST";
if (cerpadloTopi) infoText += " | Cerpadlo topi";
if (saunaAktivni) infoText += " | Sauna";
if (autoNabijeni) infoText += " | Auto nabiji";
node.status({fill: manualMod !== "auto" ? "blue" : "green", shape:"dot", text: "Mod: " + currentMode + " " + modeSource + infoText});

// v2.1: Pв”јГ–epnout z nabв”ңЕҹjenв”ңЕҹ na в”јГӯetв”јГ–it jakmile SOC dosв”ңГӯhne cв”ңЕҹle
if (currentMode === "nabijet_ze_site" && manualMod === "auto") {
    var targetSoc = (plan && plan.smartCharging) ? plan.smartCharging.targetSocFromGrid : 0;
    var currentSoc = (global.get("fve_status") || {}).battery_soc || 0;
    if (targetSoc > 0 && currentSoc >= targetSoc) {
        currentMode = "setrit";
        global.set("fve_current_mode", currentMode);
        node.status({fill:"yellow", shape:"dot", text:"SOC " + Math.round(currentSoc) + "% >= cв”ңЕҹl " + targetSoc + "% Г”ДҮДә в”јГЎetв”јГ–it"});
    }
}

msg.currentMode = currentMode;

return msg;

var mode = msg.currentMode;
var skipBattery = msg.skipBatteryControl || false;

switch (mode) {
    case "normal": msg.modeIndex = 0; break;
    case "setrit": msg.modeIndex = 1; break;
    case "nabijet_ze_site": msg.modeIndex = 2; break;
    case "prodavat": msg.modeIndex = 3; break;
    case "zakaz_pretoku": msg.modeIndex = 4; break;
    case "solar_charging": msg.modeIndex = 5; break;
    default: msg.modeIndex = 0;
}

msg.skipBatteryControl = skipBattery;
return msg;

var state = msg.payload;
var chargingStates = ["Charging", "Nabв”ңЕҹjenв”ңЕҹ", "2"];
var isCharging = chargingStates.some(function(s) {
    return state.toLowerCase().indexOf(s.toLowerCase()) !== -1 || state === s;
});
msg.autoNabijeni = isCharging;
node.status({fill: isCharging ? "yellow" : "green", shape:"dot", text: isCharging ? "Auto se nabв”ңЕҹjв”ңЕҹ" : "Auto se nenabв”ңЕҹjв”ңЕҹ"});
// Output 2: pouze pв”јГ–i zastavenв”ңЕҹ nabв”ңЕҹjenв”ңЕҹ Г”ДҮДә reset min_soc + pв”јГ–epoв”ҖЕ№et plв”ңГӯnu
if (!isCharging) {
    // Resetuj config.min_soc v globв”ңГӯlu na vв”ңЕ»chozв”ңЕҹ hodnotu
    var config = global.get("fve_config") || {};
    var defaultMinSoc = 20;
    config.min_soc = defaultMinSoc;
    global.set("fve_config", config);
    node.status({fill: "green", shape: "dot", text: "Auto STOP Г”ДҮДә reset minSoc=" + defaultMinSoc + "%, retrigger plan"});
    return [msg, msg];
}
return [msg, null];

// Nahraв”ҖДҶ starв”ңГӯ data в”ҖЕ№erstvв”ңЕ»mi z DB
var freshPrices = msg.payload || [];
if (freshPrices.length > 0) {
    msg.planData.prices = freshPrices;
    // Aktualizuj i global pro ostatnв”ңЕҹ
    global.set("fve_prices_forecast", freshPrices);
    node.status({fill:"green", shape:"dot", text: freshPrices.length + " cen z DB"});
} else {
    node.status({fill:"yellow", shape:"dot", text: "DB prв”ңГӯzdnв”ңГӯ, pouв”јЕјit global"});
}
return msg;

var state = msg.payload;
var isActive = (state === "on");
global.set("sauna_aktivni", isActive);
node.status({fill: isActive ? "red" : "green", shape: "dot", text: isActive ? "Sauna ON" : "Sauna OFF"});
// Output 1: vв”јЕјdy (logovв”ңГӯnв”ңЕҹ)
// Output 2: pouze pв”јГ–i vypnutв”ңЕҹ Г”ДҮДә reset min_soc + pв”јГ–epoв”ҖЕ№et plв”ңГӯnu
if (!isActive) {
    // Resetuj config.min_soc v globв”ңГӯlu na vв”ңЕ»chozв”ңЕҹ hodnotu (pв”јГ–edejde planovв”ңГӯnв”ңЕҹ s min_soc=74%)
    var config = global.get("fve_config") || {};
    var defaultMinSoc = 20;
    config.min_soc = defaultMinSoc;
    global.set("fve_config", config);
    node.status({fill: "green", shape: "dot", text: "Sauna OFF Г”ДҮДә reset minSoc=" + defaultMinSoc + "%, retrigger plan"});
    return [msg, msg];
}
return [msg, null];

var planData = global.get("fve_plan") || {};
var currentMode = planData.currentMode || "normal";
var currentHour = planData.currentHour || new Date().getHours();
var planArray = planData.plan || [];
var blokaceText = (planData.status && planData.status.blokaceText) ? planData.status.blokaceText : "NE";

msg.payload = JSON.stringify({
    current_mode: currentMode,
    current_reason: planData.currentReason || "",
    current_hour: currentHour,
    plan: planArray,
    soc: planData.status ? planData.status.soc : null,
    forecast_dnes: planData.status ? planData.status.forecastDnes : null,
    forecast_zitra: planData.status ? planData.status.forecastZitra : null,
    debug: planData.debug || "",
    blokace_text: blokaceText,
    last_update: new Date().toISOString()
}, null, 2);

return msg;

// Po vypnutв”ңЕҹ sauny okamв”јЕјitв”ҖЕӨ pв”јГ–epoв”ҖЕ№в”ңЕҹtej plв”ңГӯn
// (aby se min_soc=20% projevilo hned, ne aв”јЕј za minutu)
node.status({fill:"blue", shape:"dot", text:"Г”ДҮДә pв”јГ–epoв”ҖЕ№et plв”ңГӯnu"});
msg.payload = Date.now();
return msg;

// Po zastavenв”ңЕҹ nabв”ңЕҹjenв”ңЕҹ auta okamв”јЕјitв”ҖЕӨ pв”јГ–epoв”ҖЕ№в”ңЕҹtej plв”ңГӯn
node.status({fill:"blue", shape:"dot", text:"Г”ДҮДә pв”јГ–epoв”ҖЕ№et plв”ңГӯnu"});
msg.payload = Date.now();
return msg;
